     1Ôćĺ#!/usr/bin/env bun
     2Ôćĺ/**
     3Ôćĺ * AutoWorkCreation.hook.ts - Session/Task Management (UserPromptSubmit)
     4Ôćĺ *
     5Ôćĺ * PURPOSE:
     6Ôćĺ * Creates and manages the session/task hierarchy for each Claude Code session.
     7Ôćĺ * - SESSION: One directory per Claude Code session (the primitive)
     8Ôćĺ * - TASK: Subdirectories for distinct work items within a session
     9Ôćĺ *
    10Ôćĺ * Each task has its own algorithm execution context (ISC.json, THREAD.md).
    11Ôćĺ *
    12Ôćĺ * TRIGGER: UserPromptSubmit
    13Ôćĺ *
    14Ôćĺ * STRUCTURE CREATED:
    15Ôćĺ * WORK/{timestamp}_{session-title}/
    16Ôćĺ * ÔöťÔöÇÔöÇ META.yaml                    # Session metadata
    17Ôćĺ * ÔöťÔöÇÔöÇ tasks/
    18Ôćĺ * Ôöé   ÔöťÔöÇÔöÇ 001_{task-slug}/
    19Ôćĺ * Ôöé   Ôöé   ÔöťÔöÇÔöÇ ISC.json             # Task's Ideal State Criteria
    20Ôćĺ * Ôöé   Ôöé   ÔööÔöÇÔöÇ THREAD.md            # Task's algorithm log (includes metadata in frontmatter)
    21Ôćĺ * Ôöé   ÔööÔöÇÔöÇ current -> 001_...       # Symlink to active task
    22Ôćĺ * ÔööÔöÇÔöÇ scratch/                     # Temporary files
    23Ôćĺ */
    24Ôćĺ
    25Ôćĺimport { mkdirSync, existsSync, readFileSync, writeFileSync, symlinkSync, unlinkSync, lstatSync } from 'fs';
    26Ôćĺimport { join } from 'path';
    27Ôćĺimport { getPSTComponents, getISOTimestamp } from './lib/time';
    28Ôćĺimport { inference } from '../skills/PAI/Tools/Inference';
    29Ôćĺimport { PLATFORM } from './lib/platform-paths';
    30Ôćĺimport { getPaiDir } from './lib/paths';
    31Ôćĺ
    32Ôćĺinterface HookInput {
    33Ôćĺ  session_id: string;
    34Ôćĺ  prompt?: string;
    35Ôćĺ  user_prompt?: string;
    36Ôćĺ}
    37Ôćĺ
    38Ôćĺinterface CurrentWork {
    39Ôćĺ  session_id: string;
    40Ôćĺ  session_dir: string;
    41Ôćĺ  current_task: string;
    42Ôćĺ  task_count: number;
    43Ôćĺ  created_at: string;
    44Ôćĺ}
    45Ôćĺ
    46Ôćĺinterface PromptClassification {
    47Ôćĺ  type: 'work' | 'question' | 'conversational';
    48Ôćĺ  title: string;
    49Ôćĺ  effort: 'TRIVIAL' | 'QUICK' | 'STANDARD' | 'THOROUGH';
    50Ôćĺ  is_new_topic: boolean;
    51Ôćĺ}
    52Ôćĺ
    53Ôćĺ// Cross-platform path resolution using getPaiDir from lib/paths
    54Ôćĺconst BASE_DIR = getPaiDir();
    55Ôćĺconst WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    56Ôćĺconst STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    57Ôćĺconst CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    58Ôćĺ
    59Ôćĺconst CLASSIFICATION_PROMPT = `Classify this user request. Return ONLY valid JSON:
    60Ôćĺ{
    61Ôćĺ  "type": "work" | "question" | "conversational",
    62Ôćĺ  "title": "<3-8 word title>",
    63Ôćĺ  "effort": "TRIVIAL" | "QUICK" | "STANDARD" | "THOROUGH",
    64Ôćĺ  "is_new_topic": true | false
    65Ôćĺ}
    66Ôćĺ
    67ÔćĺDEFINITIONS:
    68Ôćĺ- type: work (task/imperative), question (info request), conversational (greeting/thanks)
    69Ôćĺ- effort: TRIVIAL (<5 min), QUICK (5-30 min), STANDARD (30 min - 2 hrs), THOROUGH (2+ hrs)
    70Ôćĺ- is_new_topic: true if this is a distinctly different topic from previous context, false if continuation
    71Ôćĺ
    72ÔćĺCONTEXT FOR is_new_topic:
    73Ôćĺ- true: "Now let's work on authentication" (new domain)
    74Ôćĺ- true: "Different question - how do I..." (explicit topic change)
    75Ôćĺ- false: "Also update the..." (continuation)
    76Ôćĺ- false: "What about..." (follow-up on same topic)
    77Ôćĺ- false: "Proceed" or "Yes" (confirmation)`;
    78Ôćĺ
    79Ôćĺasync function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    80Ôćĺ  return new Promise((resolve, reject) => {
    81Ôćĺ    let data = '';
    82Ôćĺ    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    83Ôćĺ    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    84Ôćĺ    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    85Ôćĺ    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
    86Ôćĺ  });
    87Ôćĺ}
    88Ôćĺ
    89Ôćĺfunction readCurrentWork(): CurrentWork | null {
    90Ôćĺ  try {
    91Ôćĺ    if (!existsSync(CURRENT_WORK_FILE)) return null;
    92Ôćĺ    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
    93Ôćĺ  } catch {
    94Ôćĺ    return null;
    95Ôćĺ  }
    96Ôćĺ}
    97Ôćĺ
    98Ôćĺfunction writeCurrentWork(state: CurrentWork): void {
    99Ôćĺ  if (!existsSync(STATE_DIR)) mkdirSync(STATE_DIR, { recursive: true });
   100Ôćĺ  writeFileSync(CURRENT_WORK_FILE, JSON.stringify(state, null, 2), 'utf-8');
   101Ôćĺ}
   102Ôćĺ
   103Ôćĺfunction slugify(text: string, maxLen: number = 40): string {
   104Ôćĺ  return text
   105Ôćĺ    .toLowerCase()
   106Ôćĺ    .replace(/[^a-z0-9\s-]/g, '')
   107Ôćĺ    .replace(/\s+/g, '-')
   108Ôćĺ    .replace(/-+/g, '-')
   109Ôćĺ    .substring(0, maxLen)
   110Ôćĺ    .replace(/-$/, '') || 'task';
   111Ôćĺ}
   112Ôćĺ
   113Ôćĺfunction generateSessionDirName(title: string): string {
   114Ôćĺ  const { year, month, day, hours, minutes, seconds } = getPSTComponents();
   115Ôćĺ  const timestamp = `${year}${month}${day}-${hours}${minutes}${seconds}`;
   116Ôćĺ  return `${timestamp}_${slugify(title, 50)}`;
   117Ôćĺ}
   118Ôćĺ
   119Ôćĺ/**
   120Ôćĺ * Create session directory structure
   121Ôćĺ */
   122Ôćĺfunction createSessionDirectory(sessionDirName: string, sessionId: string, title: string): string {
   123Ôćĺ  const sessionPath = join(WORK_DIR, sessionDirName);
   124Ôćĺ  const timestamp = getISOTimestamp();
   125Ôćĺ
   126Ôćĺ  // Create session structure
   127Ôćĺ  mkdirSync(join(sessionPath, 'tasks'), { recursive: true });
   128Ôćĺ  mkdirSync(join(sessionPath, 'scratch'), { recursive: true });
   129Ôćĺ
   130Ôćĺ  // Session META.yaml
   131Ôćĺ  const meta = `id: "${sessionDirName}"
   132Ôćĺtitle: "${title}"
   133Ôćĺsession_id: "${sessionId}"
   134Ôćĺcreated_at: "${timestamp}"
   135Ôćĺstatus: "ACTIVE"
   136Ôćĺ`;
   137Ôćĺ  writeFileSync(join(sessionPath, 'META.yaml'), meta, 'utf-8');
   138Ôćĺ
   139Ôćĺ  console.error(`[AutoWork] Created session: ${sessionPath}`);
   140Ôćĺ  return sessionPath;
   141Ôćĺ}
   142Ôćĺ
   143Ôćĺ/**
   144Ôćĺ * Create task directory with ISC.json and THREAD.md (with frontmatter metadata)
   145Ôćĺ */
   146Ôćĺfunction createTaskDirectory(
   147Ôćĺ  sessionPath: string,
   148Ôćĺ  taskNumber: number,
   149Ôćĺ  title: string,
   150Ôćĺ  effort: string,
   151Ôćĺ  prompt: string
   152Ôćĺ): string {
   153Ôćĺ  const taskId = String(taskNumber).padStart(3, '0');
   154Ôćĺ  const taskSlug = slugify(title);
   155Ôćĺ  const taskDirName = `${taskId}_${taskSlug}`;
   156Ôćĺ  const taskPath = join(sessionPath, 'tasks', taskDirName);
   157Ôćĺ  const timestamp = getISOTimestamp();
   158Ôćĺ
   159Ôćĺ  mkdirSync(taskPath, { recursive: true });
   160Ôćĺ
   161Ôćĺ  // Task THREAD.md with frontmatter metadata (no separate META.yaml)
   162Ôćĺ  const thread = `---
   163ÔćĺtaskId: "${taskDirName}"
   164Ôćĺtitle: "${title}"
   165ÔćĺeffortLevel: "${effort}"
   166Ôćĺstatus: "IN_PROGRESS"
   167ÔćĺcreatedAt: "${timestamp}"
   168Ôćĺprompt: |
   169Ôćĺ  ${prompt.substring(0, 500).replace(/\n/g, '\n  ')}
   170Ôćĺ---
   171Ôćĺ
   172Ôćĺ# Algorithm Thread: ${title}
   173Ôćĺ
   174Ôćĺ## Phase Log
   175Ôćĺ
   176Ôćĺ### ­čĹÇ OBSERVE Phase
   177Ôćĺ_Pending..._
   178Ôćĺ
   179Ôćĺ### ­čžá THINK Phase
   180Ôćĺ_Pending..._
   181Ôćĺ
   182Ôćĺ### ­čôő PLAN Phase
   183Ôćĺ_Pending..._
   184Ôćĺ
   185Ôćĺ### ­čöĘ BUILD Phase
   186Ôćĺ_Pending..._
   187Ôćĺ
   188Ôćĺ### ÔľÂ´ŞĆ EXECUTE Phase
   189Ôćĺ_Pending..._
   190Ôćĺ
   191Ôćĺ### Ôťů VERIFY Phase
   192Ôćĺ_Pending..._
   193Ôćĺ
   194Ôćĺ### ­čÄô LEARN Phase
   195Ôćĺ_Pending..._
   196Ôćĺ
   197Ôćĺ---
   198Ôćĺ
   199Ôćĺ## ISC Evolution
   200Ôćĺ
   201Ôćĺ_Criteria updates logged here..._
   202Ôćĺ
   203Ôćĺ---
   204Ôćĺ
   205Ôćĺ## Key Observations
   206Ôćĺ
   207Ôćĺ_Important observations during execution..._
   208Ôćĺ`;
   209Ôćĺ  writeFileSync(join(taskPath, 'THREAD.md'), thread, 'utf-8');
   210Ôćĺ
   211Ôćĺ  // Task ISC.json with proper scaffold
   212Ôćĺ  const isc = {
   213Ôćĺ    taskId: taskDirName,
   214Ôćĺ    status: 'PENDING',
   215Ôćĺ    effortLevel: effort,
   216Ôćĺ    criteria: [],
   217Ôćĺ    antiCriteria: [],
   218Ôćĺ    satisfaction: null,
   219Ôćĺ    createdAt: timestamp,
   220Ôćĺ    updatedAt: timestamp,
   221Ôćĺ  };
   222Ôćĺ  writeFileSync(join(taskPath, 'ISC.json'), JSON.stringify(isc, null, 2), 'utf-8');
   223Ôćĺ
   224Ôćĺ  // Update 'current' symlink (or directory junction on Windows)
   225Ôćĺ  const currentLink = join(sessionPath, 'tasks', 'current');
   226Ôćĺ  try {
   227Ôćĺ    if (existsSync(currentLink) || lstatSync(currentLink)) {
   228Ôćĺ      unlinkSync(currentLink);
   229Ôćĺ    }
   230Ôćĺ  } catch { /* ignore if doesn't exist */ }
   231Ôćĺ
   232Ôćĺ  // On Windows, create a junction. On Unix, create a symlink.
   233Ôćĺ  try {
   234Ôćĺ    symlinkSync(taskDirName, currentLink, PLATFORM === 'win32' ? 'junction' : undefined);
   235Ôćĺ  } catch (err) {
   236Ôćĺ    // If symlink/junction fails, copy as fallback
   237Ôćĺ    console.error('[AutoWork] Symlink/junction failed, copying directory:', err);
   238Ôćĺ    // Could implement copy fallback here if needed
   239Ôćĺ  }
   240Ôćĺ
   241Ôćĺ  console.error(`[AutoWork] Created task: ${taskPath}`);
   242Ôćĺ  return taskDirName;
   243Ôćĺ}
   244Ôćĺ
   245Ôćĺasync function classifyPrompt(prompt: string, hasExistingSession: boolean): Promise<PromptClassification> {
   246Ôćĺ  const trimmed = prompt.trim();
   247Ôćĺ
   248Ôćĺ  // Quick heuristics
   249Ôćĺ  if (trimmed.length < 15 && /^(yes|no|ok|okay|thanks|proceed|continue|go ahead|sure|got it)$/i.test(trimmed)) {
   250Ôćĺ    return { type: 'conversational', title: '', effort: 'TRIVIAL', is_new_topic: false };
   251Ôćĺ  }
   252Ôćĺ
   253Ôćĺ  // Use inference for classification
   254Ôćĺ  try {
   255Ôćĺ    const contextNote = hasExistingSession
   256Ôćĺ      ? '\n\nNOTE: There is an existing session with prior tasks. Consider if this is a continuation or new topic.'
   257Ôćĺ      : '\n\nNOTE: This is the first prompt in a new session. is_new_topic should be true.';
   258Ôćĺ
   259Ôćĺ    const result = await inference({
   260Ôćĺ      systemPrompt: CLASSIFICATION_PROMPT + contextNote,
   261Ôćĺ      userPrompt: prompt,
   262Ôćĺ      expectJson: true,
   263Ôćĺ      timeout: 10000,
   264Ôćĺ      level: 'fast',
   265Ôćĺ    });
   266Ôćĺ
   267Ôćĺ    if (result.success && result.parsed) {
   268Ôćĺ      const parsed = result.parsed as PromptClassification;
   269Ôćĺ      return {
   270Ôćĺ        type: parsed.type || 'work',
   271Ôćĺ        title: parsed.title || prompt.substring(0, 50),
   272Ôćĺ        effort: parsed.effort || 'STANDARD',
   273Ôćĺ        is_new_topic: hasExistingSession ? (parsed.is_new_topic ?? false) : true,
   274Ôćĺ      };
   275Ôćĺ    }
   276Ôćĺ  } catch (err) {
   277Ôćĺ    console.error(`[AutoWork] Classification failed: ${err}`);
   278Ôćĺ  }
   279Ôćĺ
   280Ôćĺ  // Fallback
   281Ôćĺ  return {
   282Ôćĺ    type: 'work',
   283Ôćĺ    title: prompt.substring(0, 50).replace(/[^a-zA-Z0-9\s]/g, '').trim(),
   284Ôćĺ    effort: 'STANDARD',
   285Ôćĺ    is_new_topic: !hasExistingSession,
   286Ôćĺ  };
   287Ôćĺ}
   288Ôćĺ
   289Ôćĺasync function main() {
   290Ôćĺ  try {
   291Ôćĺ    const input = await readStdinWithTimeout();
   292Ôćĺ    const data: HookInput = JSON.parse(input);
   293Ôćĺ    const prompt = data.prompt || data.user_prompt || '';
   294Ôćĺ    const sessionId = data.session_id || 'unknown';
   295Ôćĺ
   296Ôćĺ    if (!prompt || prompt.length < 2) {
   297Ôćĺ      process.exit(0);
   298Ôćĺ    }
   299Ôćĺ
   300Ôćĺ    if (!existsSync(WORK_DIR)) mkdirSync(WORK_DIR, { recursive: true });
   301Ôćĺ
   302Ôćĺ    let currentWork = readCurrentWork();
   303Ôćĺ    const isExistingSession = currentWork && currentWork.session_id === sessionId;
   304Ôćĺ
   305Ôćĺ    const classification = await classifyPrompt(prompt, !!isExistingSession);
   306Ôćĺ
   307Ôćĺ    // Skip task creation for pure conversational
   308Ôćĺ    if (classification.type === 'conversational' && !classification.is_new_topic) {
   309Ôćĺ      console.error('[AutoWork] Conversational continuation, no new task');
   310Ôćĺ      process.exit(0);
   311Ôćĺ    }
   312Ôćĺ
   313Ôćĺ    if (!isExistingSession) {
   314Ôćĺ      // New session: create session directory + first task
   315Ôćĺ      const title = classification.title || prompt.substring(0, 50);
   316Ôćĺ      const sessionDirName = generateSessionDirName(title);
   317Ôćĺ      const sessionPath = createSessionDirectory(sessionDirName, sessionId, title);
   318Ôćĺ
   319Ôćĺ      const taskDirName = createTaskDirectory(
   320Ôćĺ        sessionPath,
   321Ôćĺ        1,
   322Ôćĺ        title,
   323Ôćĺ        classification.effort,
   324Ôćĺ        prompt
   325Ôćĺ      );
   326Ôćĺ
   327Ôćĺ      currentWork = {
   328Ôćĺ        session_id: sessionId,
   329Ôćĺ        session_dir: sessionDirName,
   330Ôćĺ        current_task: taskDirName,
   331Ôćĺ        task_count: 1,
   332Ôćĺ        created_at: getISOTimestamp(),
   333Ôćĺ      };
   334Ôćĺ      writeCurrentWork(currentWork);
   335Ôćĺ
   336Ôćĺ      console.error(`[AutoWork] New session with task: ${taskDirName}`);
   337Ôćĺ    } else if (classification.is_new_topic) {
   338Ôćĺ      // Existing session, new topic: create new task
   339Ôćĺ      const sessionPath = join(WORK_DIR, currentWork!.session_dir);
   340Ôćĺ      const newTaskNumber = currentWork!.task_count + 1;
   341Ôćĺ      const title = classification.title || prompt.substring(0, 50);
   342Ôćĺ
   343Ôćĺ      const taskDirName = createTaskDirectory(
   344Ôćĺ        sessionPath,
   345Ôćĺ        newTaskNumber,
   346Ôćĺ        title,
   347Ôćĺ        classification.effort,
   348Ôćĺ        prompt
   349Ôćĺ      );
   350Ôćĺ
   351Ôćĺ      currentWork!.current_task = taskDirName;
   352Ôćĺ      currentWork!.task_count = newTaskNumber;
   353Ôćĺ      writeCurrentWork(currentWork!);
   354Ôćĺ
   355Ôćĺ      console.error(`[AutoWork] New task in session: ${taskDirName}`);
   356Ôćĺ    } else {
   357Ôćĺ      // Continuation of current task - no new task needed
   358Ôćĺ      console.error(`[AutoWork] Continuing task: ${currentWork!.current_task}`);
   359Ôćĺ    }
   360Ôćĺ
   361Ôćĺ    process.exit(0);
   362Ôćĺ  } catch (err) {
   363Ôćĺ    console.error(`[AutoWork] Error: ${err}`);
   364Ôćĺ    process.exit(0);
   365Ôćĺ  }
   366Ôćĺ}
   367Ôćĺ
   368Ôćĺmain();
