     1Ôćĺ/**
     2Ôćĺ * ResponseCapture.ts - Response Capture Handler
     3Ôćĺ *
     4Ôćĺ * PURPOSE:
     5Ôćĺ * Captures completed responses and updates task status.
     6Ôćĺ * Also handles learning capture for significant insights and sends notifications.
     7Ôćĺ * Extracts and persists ISC (Ideal State Criteria) to current task's ISC.json.
     8Ôćĺ *
     9Ôćĺ * STRUCTURE:
    10Ôćĺ * Session: WORK/{session_dir}/
    11Ôćĺ * Task: WORK/{session_dir}/tasks/{current_task}/
    12Ôćĺ *   - ISC.json (task's criteria)
    13Ôćĺ *   - THREAD.md (task's algorithm log with frontmatter metadata)
    14Ôćĺ */
    15Ôćĺ
    16Ôćĺimport { readFileSync, writeFileSync, mkdirSync, existsSync } from 'fs';
    17Ôćĺimport { join } from 'path';
    18Ôćĺimport { getPaiDir } from '../lib/paths';
    19Ôćĺimport { sendEventToObservability, getCurrentTimestamp, getSourceApp } from '../lib/observability';
    20Ôćĺimport { notifyTaskComplete, notifyError, getSessionDurationMinutes } from '../lib/notifications';
    21Ôćĺimport { getLearningCategory, isLearningCapture } from '../lib/learning-utils';
    22Ôćĺimport { getPSTTimestamp, getPSTDate, getYearMonth, getISOTimestamp } from '../lib/time';
    23Ôćĺimport type { ParsedTranscript, StructuredResponse } from '../../skills/PAI/Tools/TranscriptParser';
    24Ôćĺ
    25Ôćĺconst BASE_DIR = getPaiDir();
    26Ôćĺconst WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    27Ôćĺconst STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    28Ôćĺconst CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    29Ôćĺ
    30Ôćĺ// ============================================================================
    31Ôćĺ// Types
    32Ôćĺ// ============================================================================
    33Ôćĺ
    34Ôćĺinterface CurrentWork {
    35Ôćĺ  session_id: string;
    36Ôćĺ  session_dir: string;
    37Ôćĺ  current_task: string;
    38Ôćĺ  task_count: number;
    39Ôćĺ  created_at: string;
    40Ôćĺ}
    41Ôćĺ
    42Ôćĺinterface HookInput {
    43Ôćĺ  session_id: string;
    44Ôćĺ  transcript_path: string;
    45Ôćĺ  hook_event_name: string;
    46Ôćĺ}
    47Ôćĺ
    48Ôćĺtype EffortLevel = 'QUICK' | 'STANDARD' | 'THOROUGH' | 'TRIVIAL';
    49Ôćĺ
    50Ôćĺinterface ISCDocument {
    51Ôćĺ  taskId: string;
    52Ôćĺ  status: string;
    53Ôćĺ  effortLevel: string;
    54Ôćĺ  criteria: string[];
    55Ôćĺ  antiCriteria: string[];
    56Ôćĺ  satisfaction: {
    57Ôćĺ    satisfied: number;
    58Ôćĺ    partial: number;
    59Ôćĺ    failed: number;
    60Ôćĺ    total: number;
    61Ôćĺ  } | null;
    62Ôćĺ  createdAt: string;
    63Ôćĺ  updatedAt: string;
    64Ôćĺ}
    65Ôćĺ
    66Ôćĺ// ============================================================================
    67Ôćĺ// ISC Extraction Helpers
    68Ôćĺ// ============================================================================
    69Ôćĺ
    70Ôćĺfunction extractEffortLevel(text: string): EffortLevel | null {
    71Ôćĺ  const match = text.match(/level\s+(QUICK|STANDARD|THOROUGH|TRIVIAL)/i);
    72Ôćĺ  return match ? (match[1].toUpperCase() as EffortLevel) : null;
    73Ôćĺ}
    74Ôćĺ
    75Ôćĺfunction extractISCSatisfaction(text: string): ISCDocument['satisfaction'] | null {
    76Ôćĺ  // Match patterns like "6 ISC criteria, all satisfied"
    77Ôćĺ  const allSatisfied = text.match(/(\d+)\s*(?:ISC\s*)?criteria?,?\s*all\s*satisfied/i);
    78Ôćĺ  if (allSatisfied) {
    79Ôćĺ    const total = parseInt(allSatisfied[1], 10);
    80Ôćĺ    return { satisfied: total, partial: 0, failed: 0, total };
    81Ôćĺ  }
    82Ôćĺ
