    99Ôćĺ
   100Ôćĺ    // Handle array items
   101Ôćĺ    if (trimmed.startsWith('- ') && inArray) {
   102Ôćĺ      const value = trimmed.slice(2).replace(/^["']|["']$/g, '');
   103Ôćĺ      if (arrayKey === 'lineage') {
   104Ôćĺ        // Nested array in lineage
   105Ôćĺ        const lastKey = Object.keys(meta.lineage).pop();
   106Ôćĺ        if (lastKey) meta.lineage[lastKey].push(value);
   107Ôćĺ      } else {
   108Ôćĺ        meta[arrayKey].push(value);
   109Ôćĺ      }
   110Ôćĺ      continue;
   111Ôćĺ    }
   112Ôćĺ
   113Ôćĺ    // Handle key: value pairs
   114Ôćĺ    const match = trimmed.match(/^([a-z_]+):\s*(.*)$/);
   115Ôćĺ    if (match) {
   116Ôćĺ      const [, key, value] = match;
   117Ôćĺ      currentKey = key;
   118Ôćĺ
   119Ôćĺ      if (key === 'lineage') {
   120Ôćĺ        meta.lineage = { tools_used: [], files_changed: [], agents_spawned: [] };
   121Ôćĺ        inArray = false;
   122Ôćĺ        continue;
   123Ôćĺ      }
   124Ôćĺ
   125Ôćĺ      if (value === '[]') {
   126Ôćĺ        if (meta.lineage) {
   127Ôćĺ          meta.lineage[key] = [];
   128Ôćĺ        } else {
   129Ôćĺ          meta[key] = [];
   130Ôćĺ        }
   131Ôćĺ        inArray = false;
   132Ôćĺ      } else if (value === '') {
   133Ôćĺ        if (meta.lineage && ['tools_used', 'files_changed', 'agents_spawned'].includes(key)) {
   134Ôćĺ          meta.lineage[key] = [];
   135Ôćĺ          arrayKey = 'lineage';
   136Ôćĺ          inArray = true;
   137Ôćĺ        } else {
   138Ôćĺ          meta[key] = [];
   139Ôćĺ          arrayKey = key;
   140Ôćĺ          inArray = true;
   141Ôćĺ        }
