   146Ôćĺ        } else {
   147Ôćĺ          meta[key] = cleanValue === 'null' ? null : cleanValue;
   148Ôćĺ        }
   149Ôćĺ        inArray = false;
   150Ôćĺ      }
   151Ôćĺ    }
   152Ôćĺ  }
