    88Ôćĺasync function findTaskResult(transcriptPath: string, maxAttempts: number = 2): Promise<{ result: string | null, agentType: string | null, description: string | null, toolInput: any | null }> {
    89Ôćĺ  console.error(`­čôé Looking for Task result in transcript: ${transcriptPath}`);
    90Ôćĺ
    91Ôćĺ  // If the provided transcript path doesn't exist, try to find the most recent agent transcript
    92Ôćĺ  let actualTranscriptPath = transcriptPath;
    93Ôćĺ
    94Ôćĺ  // PERFORMANCE FIX: Reduced from 6 attempts (10+ seconds) to 2 attempts (~500ms)
    95Ôćĺ  // The transcript should already exist when SubagentStop fires
    96Ôćĺ  // If it doesn't exist after a quick check, don't block - just exit gracefully
    97Ôćĺ  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    98Ôćĺ    if (attempt > 0) {
    99Ôćĺ      // Single short retry - 200ms is enough for filesystem sync
   100Ôćĺ      await delay(200);
   101Ôćĺ    }
   102Ôćĺ
   103Ôćĺ    if (!existsSync(actualTranscriptPath)) {
   104Ôćĺ      console.error(`ÔŁî Transcript file doesn't exist: ${actualTranscriptPath} (attempt ${attempt + 1}/${maxAttempts})`);
   105Ôćĺ
   106Ôćĺ      // Try to find agent transcript in the same directory
   107Ôćĺ      const dir = require('path').dirname(transcriptPath);
   108Ôćĺ      if (existsSync(dir)) {
   109Ôćĺ        const { readdirSync, statSync } = require('fs');
   110Ôćĺ        const files = readdirSync(dir)
   111Ôćĺ          .filter((f: string) => f.startsWith('agent-') && f.endsWith('.jsonl'))
   112Ôćĺ          .map((f: string) => ({ name: f, mtime: statSync(join(dir, f)).mtime }))
   113Ôćĺ          .sort((a: any, b: any) => b.mtime - a.mtime);
   114Ôćĺ
   115Ôćĺ        if (files.length > 0) {
   116Ôćĺ          actualTranscriptPath = join(dir, files[0].name);
   117Ôćĺ          console.error(`­čöä Found recent agent transcript: ${actualTranscriptPath}`);
   118Ôćĺ        }
   119Ôćĺ      }
   120Ôćĺ
   121Ôćĺ      if (!existsSync(actualTranscriptPath)) {
   122Ôćĺ        continue;
   123Ôćĺ      }
   124Ôćĺ    }
   125Ôćĺ
   126Ôćĺ    try {
   127Ôćĺ      const transcript = readFileSync(actualTranscriptPath, 'utf-8');
   128Ôćĺ      const lines = transcript.trim().split('\n');
   129Ôćĺ
   130Ôćĺ      // Search from the end of the transcript backwards
   131Ôćĺ      for (let i = lines.length - 1; i >= 0; i--) {
   132Ôćĺ        try {
   133Ôćĺ          const entry = JSON.parse(lines[i]);
   134Ôćĺ
   135Ôćĺ          // Look for assistant messages that contain Task tool_use
   136Ôćĺ          if (entry.type === 'assistant' && entry.message?.content) {
   137Ôćĺ            for (const content of entry.message.content) {
   138Ôćĺ              if (content.type === 'tool_use' && content.name === 'Task') {
   139Ôćĺ                const toolInput = content.input;
   140Ôćĺ                const description = toolInput?.description || null;
   141Ôćĺ                console.error(`Ôťů Found Task invocation with subagent: ${toolInput?.subagent_type}, description: ${description}`);
   142Ôćĺ                // Found a Task invocation, now look for its result
   143Ôćĺ                // The result should be in a subsequent user message
   144Ôćĺ                for (let j = i + 1; j < lines.length; j++) {
   145Ôćĺ                  const resultEntry = JSON.parse(lines[j]);
   146Ôćĺ                  if (resultEntry.type === 'user' && resultEntry.message?.content) {
   147Ôćĺ                    for (const resultContent of resultEntry.message.content) {
   148Ôćĺ                      if (resultContent.type === 'tool_result' && resultContent.tool_use_id === content.id) {
   149Ôćĺ                        // Found the matching Task result
   150Ôćĺ                        // Content can be either a string or an array of objects with text
   151Ôćĺ                        let taskOutput: string;
   152Ôćĺ                        if (typeof resultContent.content === 'string') {
   153Ôćĺ                          taskOutput = resultContent.content;
   154Ôćĺ                        } else if (Array.isArray(resultContent.content)) {
   155Ôćĺ                          // Extract text from array of content objects
   156Ôćĺ                          taskOutput = resultContent.content
   157Ôćĺ                            .filter((item: any) => item.type === 'text')
   158Ôćĺ                            .map((item: any) => item.text)
   159Ôćĺ                            .join('\n');
   160Ôćĺ                        } else {
   161Ôćĺ                          console.error('ÔŁî Unexpected tool_result content type');
   162Ôćĺ                          continue;
   163Ôćĺ                        }
   164Ôćĺ
   165Ôćĺ                        // Extract agent type from the output
   166Ôćĺ                        let agentType = 'default';
   167Ôćĺ                        const agentMatch = taskOutput.match(/Sub-agent\s+(\w+)\s+completed/i);
   168Ôćĺ                        if (agentMatch) {
   169Ôćĺ                          agentType = agentMatch[1].toLowerCase();
   170Ôćĺ                        }
   171Ôćĺ
   172Ôćĺ                        return { result: taskOutput, agentType, description, toolInput };
   173Ôćĺ                      }
   174Ôćĺ                    }
   175Ôćĺ                  }
   176Ôćĺ                }
   177Ôćĺ              }
   178Ôćĺ            }
   179Ôćĺ          }
   180Ôćĺ        } catch (e) {
   181Ôćĺ          // Invalid JSON line, skip
   182Ôćĺ        }
   183Ôćĺ      }
   184Ôćĺ    } catch (e) {
   185Ôćĺ      // Error reading file, will retry
   186Ôćĺ    }
   187Ôćĺ  }
   188Ôćĺ
   189Ôćĺ  return { result: null, agentType: null, description: null, toolInput: null };
   190Ôćĺ}
