   192Ôćĺfunction extractCompletionMessage(taskOutput: string): { message: string | null, agentType: string | null } {
   193Ôćĺ  console.error('­čöŹ DEBUG - Extracting from task output, length:', taskOutput.length);
   194Ôćĺ  console.error('­čöŹ DEBUG - First 200 chars:', taskOutput.substring(0, 200));
   195Ôćĺ  console.error('­čöŹ DEBUG - Last 200 chars:', taskOutput.substring(taskOutput.length - 200));
   196Ôćĺ
   197Ôćĺ  // Look for the COMPLETED section in the agent's output
   198Ôćĺ  // Priority: 1) New ­čŚú´ŞĆ format, 2) Legacy [AGENT:type] format
   199Ôćĺ  const agentPatterns = [
   200Ôćĺ    // NEW FORMAT: ­čŚú´ŞĆ AgentName: [text] (primary)
   201Ôćĺ    // Captures agent name dynamically from the line
   202Ôćĺ    /­čŚú´ŞĆ\s*\*{0,2}([\w-]+):?\*{0,2}\s*(.+?)(?:\n|$)/is,
   203Ôćĺ
   204Ôćĺ    // LEGACY FORMAT: ­čÄ» COMPLETED: [AGENT:type] [text] (backward compatibility)
   205Ôćĺ    // Handle markdown formatting with asterisks - same line
   206Ôćĺ    /\*+­čÄ»\s*COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   207Ôćĺ    /\*+­čÄ»\s+COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   208Ôćĺ    // Non-markdown patterns - same line
   209Ôćĺ    /­čÄ»\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   210Ôćĺ    /COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   211Ôćĺ
   212Ôćĺ    // Multi-line patterns (emoji/COMPLETED on one line, AGENT tag on next)
   213Ôćĺ    /­čÄ»\s*COMPLETED[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   214Ôćĺ    /##\s*­čÄ»\s*COMPLETED[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   215Ôćĺ    /\*+­čÄ»\s*COMPLETED\*+[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   216Ôćĺ
   217Ôćĺ    // Generic pattern for current format
   218Ôćĺ    /­čÄ».*COMPLETED.*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   219Ôćĺ
   220Ôćĺ    // OLD: Handle legacy "I completed" format (for backward compatibility)
   221Ôćĺ    /\*+­čÄ»\s*COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   222Ôćĺ    /\*+­čÄ»\s+COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   223Ôćĺ    /­čÄ»\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   224Ôćĺ    /COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   225Ôćĺ    /\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\.|!|\n|$)/is,
   226Ôćĺ    /­čÄ».*COMPLETED.*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is
   227Ôćĺ  ];
   228Ôćĺ
   229Ôćĺ  // First try to match agent-specific patterns
   230Ôćĺ  for (const pattern of agentPatterns) {
   231Ôćĺ    const match = taskOutput.match(pattern);
   232Ôćĺ    if (match && match[1] && match[2]) {
   233Ôćĺ      const agentType = match[1].toLowerCase();
   234Ôćĺ      let message = match[2].trim();
   235Ôćĺ
   236Ôćĺ      // Prepend agent name for spoken message
   237Ôćĺ      const agentName = agentType.charAt(0).toUpperCase() + agentType.slice(1);
   238Ôćĺ
   239Ôćĺ      // Intelligent "completed" detection
   240Ôćĺ      // Don't say "completed" for greetings, questions, or status updates
   241Ôćĺ      const isGreeting = /^(hey|hello|hi|greetings|good morning|good afternoon|good evening)/i.test(message);
   242Ôćĺ      const isQuestion = message.includes('?');
   243Ôćĺ      const isStatusUpdate = /(ready to help|online|here|available|standing by|doing (great|well|fine))/i.test(message);
   244Ôćĺ
   245Ôćĺ      const fullMessage = (isGreeting || isQuestion || isStatusUpdate)
   246Ôćĺ        ? message  // Just the message for greetings/questions/status
   247Ôćĺ        : `${agentName} completed ${message}`;  // Prepend "completed" for tasks
   248Ôćĺ
   249Ôćĺ      console.error(`Ôťů FOUND AGENT MATCH: [${agentType}] ${fullMessage}`);
   250Ôćĺ
   251Ôćĺ      // Return agent type and message
   252Ôćĺ      return { message: fullMessage, agentType };
   253Ôćĺ    }
   254Ôćĺ  }
   255Ôćĺ
   256Ôćĺ  // Fall back to generic patterns but try to extract agent type
   257Ôćĺ  const genericPatterns = [
   258Ôćĺ    // NEW FORMAT: ­čŚú´ŞĆ [text] (without specific name - fallback)
   259Ôćĺ    /­čŚú´ŞĆ\s*(.+?)(?:\n|$)/i,
   260Ôćĺ    // LEGACY FORMAT (backward compatibility)
   261Ôćĺ    // Handle markdown formatting
   262Ôćĺ    /\*+­čÄ»\s*COMPLETED:\*+\s*(.+?)(?:\n|$)/i,
   263Ôćĺ    /\*+COMPLETED:\*+\s*(.+?)(?:\n|$)/i,
   264Ôćĺ    // Non-markdown patterns
   265Ôćĺ    /­čÄ»\s*COMPLETED:\s*(.+?)(?:\n|$)/i,
   266Ôćĺ    /COMPLETED:\s*(.+?)(?:\n|$)/i,
   267Ôćĺ    /Sub-agent\s+\w+\s+completed\s+(.+?)(?:\.|!|\n|$)/i,
   268Ôćĺ    /Agent\s+completed\s+(.+?)(?:\.|!|\n|$)/i
   269Ôćĺ  ];
   270Ôćĺ
   271Ôćĺ  for (const pattern of genericPatterns) {
   272Ôćĺ    const match = taskOutput.match(pattern);
   273Ôćĺ    if (match && match[1]) {
   274Ôćĺ      let message = match[1].trim();
   275Ôćĺ
   276Ôćĺ      // Basic cleanup
   277Ôćĺ      message = message.replace(/^(the\s+)?requested\s+task$/i, '');
   278Ôćĺ
   279Ôćĺ      // Only return if it's not a generic message
   280Ôćĺ      if (message &&
   281Ôćĺ          !message.match(/^(the\s+)?requested\s+task$/i) &&
   282Ôćĺ          !message.match(/^task$/i) &&
   283Ôćĺ          message.length > 5) {
   284Ôćĺ
   285Ôćĺ        // Try to detect agent type from context
   286Ôćĺ        let agentType = null;
   287Ôćĺ        const agentMatch = taskOutput.match(/Sub-agent\s+(\w+)\s+completed/i);
   288Ôćĺ        if (agentMatch) {
   289Ôćĺ          agentType = agentMatch[1].toLowerCase();
   290Ôćĺ        }
   291Ôćĺ
   292Ôćĺ        return { message, agentType };
   293Ôćĺ      }
   294Ôćĺ    }
   295Ôćĺ  }
   296Ôćĺ
   297Ôćĺ  return { message: null, agentType: null };
   298Ôćĺ}
