   310Ôćĺ
   311Ôćĺ  debug('­čöŹ SubagentStop hook started');
   312Ôćĺ  // Read input from stdin with timeout
   313Ôćĺ  let input = '';
   314Ôćĺ  try {
   315Ôćĺ    const decoder = new TextDecoder();
