   325Ôćĺ        if (done) break;
   326Ôćĺ        input += decoder.decode(value, { stream: true });
   327Ôćĺ      }
   328Ôćĺ    })();
   329Ôćĺ
   330Ôćĺ    await Promise.race([readPromise, timeoutPromise]);
   331Ôćĺ  } catch (e) {
   332Ôćĺ    debug(`Failed to read input: ${e}`);
   333Ôćĺ    process.exit(0);
   334Ôćĺ  }
   335Ôćĺ  
   336Ôćĺ  if (!input) {
