   458Ôćĺ  const timestamp = pstTimestamp
   459Ôćĺ    .replace(/ PST$/, '')
   460Ôćĺ    .replace(/:/g, '')
   461Ôćĺ    .replace(/ /, '-'); // YYYY-MM-DD-HHMMSS
   462Ôćĺ
