   464Ôćĺ
   465Ôćĺ  // Infer capture type from agent type
   466Ôćĺ  // All agent outputs go to RESEARCH for simplicity (consolidated structure)
   467Ôćĺ  let captureType = 'RESEARCH';
   468Ôćĺ  const category = 'RESEARCH';
   469Ôćĺ
   470Ôćĺ  if (agentType === 'researcher' || agentType.includes('researcher')) {
   471Ôćĺ    captureType = 'RESEARCH';
   472Ôćĺ  } else if (agentType === 'architect') {
   473Ôćĺ    captureType = 'DECISION';
   474Ôćĺ  } else if (agentType === 'engineer') {
