   483Ôćĺ
   484Ôćĺ  // Generate description from completion message (kebab-case, max 60 chars)
   485Ôćĺ  const description = completionMessage
   486Ôćĺ    .toLowerCase()
   487Ôćĺ    .replace(/^(architect|engineer|designer|researcher|pentester|intern)\s+completed\s+/i, '')
