   169Ôćĺfunction isExplicitRating(prompt: string): boolean {
   170Ôćĺ  const trimmed = prompt.trim();
   171Ôćĺ  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   172Ôćĺ  const match = trimmed.match(ratingPattern);
   173Ôćĺ
   174Ôćĺ  if (!match) return false;
   175Ôćĺ
   176Ôćĺ  const comment = match[2]?.trim();
   177Ôćĺ  if (comment) {
   178Ôćĺ    const sentenceStarters = /^(items?|things?|steps?|files?|lines?|bugs?|issues?|errors?|times?|minutes?|hours?|days?|seconds?|percent|%|th\b|st\b|nd\b|rd\b|of\b|in\b|at\b|to\b|the\b|a\b|an\b)/i;
   179Ôćĺ    if (sentenceStarters.test(comment)) {
   180Ôćĺ      return false;
   181Ôćĺ    }
   182Ôćĺ  }
   183Ôćĺ
   184Ôćĺ  return true;
   185Ôćĺ}
