   187Ôćĺ/**
   188Ôćĺ * Read stdin with timeout
   189Ôćĺ */
   190Ôćĺasync function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
   191Ôćĺ  return new Promise((resolve, reject) => {
   192Ôćĺ    let data = '';
   193Ôćĺ    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
   194Ôćĺ    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
   195Ôćĺ    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
   196Ôćĺ    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
   197Ôćĺ  });
   198Ôćĺ}
