   200Ôćĺ/**
   201Ôćĺ * Get recent conversation context from transcript
   202Ôćĺ */
   203Ôćĺfunction getRecentContext(transcriptPath: string, maxTurns: number = 3): string {
   204Ôćĺ  try {
   205Ôćĺ    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   206Ôćĺ
   207Ôćĺ    const content = readFileSync(transcriptPath, 'utf-8');
   208Ôćĺ    const lines = content.trim().split('\n');
   209Ôćĺ
   210Ôćĺ    const turns: { role: string; text: string }[] = [];
   211Ôćĺ
   212Ôćĺ    for (const line of lines) {
   213Ôćĺ      if (!line.trim()) continue;
   214Ôćĺ      try {
   215Ôćĺ        const entry = JSON.parse(line);
   216Ôćĺ
   217Ôćĺ        if (entry.type === 'user' && entry.message?.content) {
   218Ôćĺ          let text = '';
   219Ôćĺ          if (typeof entry.message.content === 'string') {
   220Ôćĺ            text = entry.message.content;
   221Ôćĺ          } else if (Array.isArray(entry.message.content)) {
   222Ôćĺ            text = entry.message.content
   223Ôćĺ              .filter((c: any) => c.type === 'text')
   224Ôćĺ              .map((c: any) => c.text)
   225Ôćĺ              .join(' ');
   226Ôćĺ          }
   227Ôćĺ          if (text.trim()) {
   228Ôćĺ            turns.push({ role: 'User', text: text.slice(0, 200) });
   229Ôćĺ          }
   230Ôćĺ        }
   231Ôćĺ
   232Ôćĺ        if (entry.type === 'assistant' && entry.message?.content) {
   233Ôćĺ          const text = typeof entry.message.content === 'string'
   234Ôćĺ            ? entry.message.content
   235Ôćĺ            : Array.isArray(entry.message.content)
   236Ôćĺ              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   237Ôćĺ              : '';
   238Ôćĺ          if (text) {
   239Ôćĺ            const summaryMatch = text.match(/SUMMARY:\s*([^\n]+)/i);
   240Ôćĺ            const shortText = summaryMatch ? summaryMatch[1] : text.slice(0, 150);
   241Ôćĺ            turns.push({ role: 'Assistant', text: shortText });
   242Ôćĺ          }
   243Ôćĺ        }
   244Ôćĺ      } catch {}
   245Ôćĺ    }
   246Ôćĺ
   247Ôćĺ    const recentTurns = turns.slice(-maxTurns);
   248Ôćĺ    if (recentTurns.length === 0) return '';
   249Ôćĺ
   250Ôćĺ    return recentTurns.map(t => `${t.role}: ${t.text}`).join('\n');
   251Ôćĺ  } catch {
   252Ôćĺ    return '';
   253Ôćĺ  }
   254Ôćĺ}
